#include <bits/stdc++.h>
#define int long long
#define ull unsigned long long
#define mk make_pair
#define PII pair<int,int>
#define NoAns puts("-1");
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define Yes puts("Yes");
#define No puts("No");
#define llinf 0x3f3f3f3f3f3f3f3f
#define inf 0x3f3f3f3f
#define ll long long
#define snd second
#define fst first
#define il inline
#define pb push_back
#define CI const int
#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
#define mid ((l+r)>>1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
double m,dis[MAXN],x[MAXN],y[MAXN];
int n,w,st[MAXN];
vector<pair<int,double>> g[MAXN];
double f(int i,int j)
{
	return sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]));
}
void dijkstra(int s)
{
	priority_queue<pair<double,int>,vector<pair<double,int>>,greater<>> pq;
	FOR(i,1,n)dis[i]=1e15;
	pq.push(mk(0,s));
	dis[s]=0;
	wh(pq.size())
	{
		pair<double,int> front=pq.top();
		int b=front.snd;
		pq.pop();
		if(st[b])continue;
		st[b]=true;
		FOI(u,g[b])
		{
			if(dis[u.fst]>dis[b]+u.snd)
			{
				dis[u.fst]=dis[b]+u.snd;
				pq.push(mk(dis[u.fst],u.fst));
			}
		}
	}
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cout.tie(0);
    cin>>n>>w>>m;
    FOR(i,1,n)
    {
        cin>>x[i]>>y[i];
    }
    FOR(i,1,w)
    {
        int u,v;
        cin>>u>>v;
        g[u].pb(mk(v,0));
        g[v].pb(mk(u,0));
    }
    FOR(i,1,n)
    {
        FOR(j,1,n)
        {
            if(j!=i&&f(i,j)<=m)
            {
            	g[i].pb({j,f(i,j)});
			}
        }
    }
    dijkstra(1);
	if(dis[n]==1e15)cout<<-1;
	else cout<<(int)(dis[n]*1000);
    return false;
}
